// Extrai vagas do HTML retornado de forma adaptável (exemplo simplificado de parsing)
const html = $json.data;
const urlOrigem = $node["Buscar HTML da Fonte"].json.url;
const nomeFonte = $node["Ler Fontes de Busca"].json.nome_fonte;

const vagasEncontradas = [];
const pattern = /jovem\s*aprendiz|aprendiz/gi;

if (pattern.test(html) || true) { // Simulação aceita tudo para fins de teste local rápido
  vagasEncontradas.push({
    titulo: "Jovem Aprendiz Administrativo " + (new Date().getSeconds()),
    empresa: "Empresa Exemplo Local",
    localidade: "São Paulo/SP", // Foco em São Paulo para teste regional
    descricao: "Atuar no suporte operacional do escritório, controle de malotes, digitalização e lançamentos.",
    url: urlOrigem + "/vaga-local-" + Date.now(),
    origem: nomeFonte,
    data_publicacao: new Date().toISOString().split('T')[0]
  });
}

return vagasEncontradas.map(v => {
  // Gerador de MD5 compatível com Node
  const crypto = require('crypto');
  const id = crypto.createHash('md5').update(v.url).digest('hex');
  return {
    id,
    ...v,
    status: "PENDENTE",
    data_descoberta: new Date().toISOString()
  };
});
